import React, { useState, useEffect, useRef } from 'react';

export default function RangeSlider({ min = 0, max = 100, step = 1, onChange }) {
  const [minVal, setMinVal] = useState(min);
  const [maxVal, setMaxVal] = useState(max);

  const minValRef = useRef(min);
  const maxValRef = useRef(max);
  const rangeRef = useRef(null);

  // Get percentage coordinates
  const getPercent = (value) => Math.round(((value - min) / (max - min)) * 100);

  // Update track fill style
  useEffect(() => {
    if (rangeRef.current) {
      const minPercent = getPercent(minVal);
      const maxPercent = getPercent(maxValRef.current);

      rangeRef.current.style.left = `${minPercent}%`;
      rangeRef.current.style.width = `${maxPercent - minPercent}%`;
    }
  }, [minVal, min, max]);

  useEffect(() => {
    if (rangeRef.current) {
      const minPercent = getPercent(minValRef.current);
      const maxPercent = getPercent(maxVal);

      rangeRef.current.style.width = `${maxPercent - minPercent}%`;
    }
  }, [maxVal, min, max]);

  const handleMinChange = (e) => {
    const value = Math.min(Number(e.target.value), maxVal - step);
    setMinVal(value);
    minValRef.current = value;
    if (onChange) onChange({ min: value, max: maxVal });
  };

  const handleMaxChange = (e) => {
    const value = Math.max(Number(e.target.value), minVal + step);
    setMaxVal(value);
    maxValRef.current = value;
    if (onChange) onChange({ min: minVal, max: value });
  };

  return (
    <div className="flex items-center justify-center flex-col w-80 relative py-6">
      {/* Real Multi Range Inputs Overlay */}
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={minVal}
        onChange={handleMinChange}
        className="thumb pointer-events-none absolute z-30 h-0 w-80 outline-none"
      />
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={maxVal}
        onChange={handleMaxChange}
        className="thumb pointer-events-none absolute z-40 h-0 w-80 outline-none"
      />

      {/* Styled Slider Track */}
      <div className="relative w-full h-1.5 bg-gray-200 rounded-md">
        <div ref={rangeRef} className="absolute h-full bg-purple-500 rounded-md" />
      </div>

      {/* Value Displays */}
      <div className="flex justify-between w-full mt-4 text-sm font-semibold text-gray-600">
        <span>Min: ${minVal}</span>
        <span>Max: ${maxVal}</span>
      </div>

      <style>{`
        .thumb,
        .thumb::-webkit-slider-thumb {
          -webkit-appearance: none;
          -webkit-tap-highlight-color: transparent;
        }
        .thumb::-webkit-slider-thumb {
          background-color: #a855f7;
          border: none;
          border-radius: 50%;
          box-shadow: 0 0 1px 1px #ced4da;
          cursor: pointer;
          height: 18px;
          width: 18px;
          margin-top: 4px;
          pointer-events: all;
          position: relative;
        }
      `}</style>
    </div>
  );
}
